{
  "description": "Schema for extracting key information from an invoice document.",
  "type": "object",
  "properties": {
    "invoice_number": {
      "description": "The unique identifier for the invoice.",
      "type": "string"
    },
    "invoice_date": {
      "description": "The date the invoice was issued, in YYYY-MM-DD format.",
      "type": "string"
    },
    "due_date": {
      "description": "The date the invoice payment is due, in YYYY-MM-DD format.",
      "type": "string"
    },
    "vendor_info": {
      "description": "Information about the vendor or supplier.",
      "type": "object",
      "properties": {
        "name": {
          "description": "The name of the vendor or supplier.",
          "type": "string"
        },
        "address": {
          "description": "The full address of the vendor or supplier.",
          "type": "string"
        },
        "email": {
          "description": "The email address of the vendor or supplier.",
          "type": "string"
        }
      },
      "required": [
        "name",
        "address"
      ],
      "additionalProperties": false
    },
    "bill_to_info": {
      "description": "Information about the customer or recipient of the invoice.",
      "type": "object",
      "properties": {
        "name": {
          "description": "The name of the customer or recipient.",
          "type": "string"
        },
        "address": {
          "description": "The full billing address of the customer or recipient.",
          "type": "string"
        }
      },
      "required": [
        "name",
        "address"
      ],
      "additionalProperties": false
    },
    "line_items": {
      "description": "An array of individual items or services listed on the invoice.",
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "description": {
            "description": "A description of the item or service.",
            "type": "string"
          },
          "quantity": {
            "description": "The quantity of the item or service.",
            "type": "number"
          },
          "unit_price": {
            "description": "The price per unit of the item or service.",
            "type": "number"
          },
          "amount": {
            "description": "The total amount for this line item (quantity * unit_price).",
            "type": "number"
          }
        },
        "required": [
          "description",
          "quantity",
          "unit_price",
          "amount"
        ],
        "additionalProperties": false
      }
    },
    "subtotal_amount": {
      "description": "The sum of all line item amounts before taxes and discounts.",
      "type": "number"
    },
    "tax_amount": {
      "description": "The total amount of tax applied to the invoice.",
      "type": "number"
    },
    "tax_rate": {
      "description": "The tax rate applied, expressed as a percentage (e.g., 8.875 for 8.875%).",
      "type": "number"
    },
    "total_amount": {
      "description": "The grand total amount of the invoice, including subtotal and tax.",
      "type": "number"
    },
    "payment_terms": {
      "description": "The payment terms specified on the invoice (e.g., Net 30).",
      "type": "string"
    }
  },
  "required": [
    "invoice_number",
    "invoice_date",
    "vendor_info",
    "bill_to_info",
    "line_items",
    "subtotal_amount",
    "tax_amount",
    "total_amount"
  ],
  "additionalProperties": false
}

